// Exports the generated TS data modules (lib/bars.ts, lib/neighborhoods.ts,
// lib/zips.ts) to plain JSON bundled into the SwiftUI app. The TS files remain
// the source of truth (regenerated by geocode-bars / build-* scripts); this is
// the consumer-side build step for the native app.
//
//   node scripts/export-swift-data.mjs
//
// Writes NYCGayBars/Data/Resources/{bars,neighborhoods,zips,meta}.json

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { fileURLToPath, pathToFileURL } from "node:url";
import { dirname, resolve, join } from "node:path";
import { tmpdir } from "node:os";

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, ".."); // legacy-expo (holds lib/*.ts, gay_bars.csv)
const repoRoot = resolve(here, "..", ".."); // repo root (holds NYCGayBars/)
const outDir = join(repoRoot, "NYCGayBars", "Data", "Resources");
mkdirSync(outDir, { recursive: true });

// Strip TS so the module can be imported as plain ESM, then return its exports.
async function loadTs(relPath) {
  let src = readFileSync(join(root, relPath), "utf8");
  src = src
    .split("\n")
    .filter((l) => !/^\s*import\s/.test(l) && !/^\s*export type\s/.test(l))
    .join("\n");
  // drop trailing helper functions (e.g. getBarById) — data only
  src = src.replace(/export function [\s\S]*$/m, "");
  // remove type annotations on exported consts: `export const X: T =` -> `export const X =`
  src = src.replace(/export const (\w+)\s*:\s*[^=]+=/g, "export const $1 =");
  const tmp = join(tmpdir(), `swiftdata-${Date.now()}-${Math.random().toString(36).slice(2)}.mjs`);
  writeFileSync(tmp, src);
  return import(pathToFileURL(tmp).href);
}

const bars = await loadTs("lib/bars.ts");
const hoods = await loadTs("lib/neighborhoods.ts");
const zips = await loadTs("lib/zips.ts");

const write = (name, data) => {
  writeFileSync(join(outDir, name), JSON.stringify(data, null, 2) + "\n");
  console.log(`wrote ${name}`);
};

write("bars.json", bars.BARS);
write("neighborhoods.json", hoods.NEIGHBORHOOD_POLYGONS);
write("zips.json", zips.ZIP_CENTROIDS);
write("meta.json", { neighborhoods: bars.NEIGHBORHOODS, region: bars.NYC_REGION });

console.log(`\n${bars.BARS.length} bars, ${bars.NEIGHBORHOODS.length} neighborhoods, ${Object.keys(zips.ZIP_CENTROIDS).length} zips`);
